SELECT SUM(value) AS total_value
FROM records
WHERE status = 'active' AND family_id IN (SELECT family_id FROM families WHERE family_name = 'Bonds');

SELECT family_name
FROM families
WHERE family_id = 1;

SELECT DISTINCT status 
FROM records 
WHERE family_id = (SELECT family_id FROM families WHERE family_name = 'Bonds');

SELECT COUNT(DISTINCT record_id) AS count
FROM rates
WHERE rate_id = 1;

SELECT id 
FROM records 
WHERE status = 'inactive' AND id NOT IN (
  SELECT record_id 
  FROM valuations
);
